import React from "react";
import { FullPage, Slide } from "react-full-page";
import { Link } from "react-scroll";
import GitHubIcon from "@material-ui/icons/GitHub";
import LinkedInIcon from "@material-ui/icons/LinkedIn";
import IconButton from "@material-ui/core/IconButton";
import { AppBar, Toolbar, Button, Grid } from "@material-ui/core";
import { spacing } from "@material-ui/system";

class Header extends React.Component {
  static propTypes = {
    className: PropTypes.string,
    getCurrentSlideIndex: PropTypes.func.isRequired,
    onNext: PropTypes.func.isRequired,
    onPrev: PropTypes.func.isRequired,
    scrollToSlide: PropTypes.func.isRequired,
    slidesCount: PropTypes.number.isRequired,
    style: PropTypes.object,
  };

  render() {
    return (
      <AppBar position="sticky">
        <Toolbar variant="dense">
          <Grid
            container
            alignItems="center"
            direction="row"
            justify="space-between"
          >
            <div>
              <IconButton
                aria-label="Linkedin.com"
                onClick={() =>
                  window.open("https://www.linkedin.com/in/richard-woessner/")
                }
              >
                <LinkedInIcon color="action" />
              </IconButton>

              <IconButton
                aria-label="GitHub.com"
                onClick={() =>
                  window.open("https://github.com/Richard-Woessner")
                }
              >
                <GitHubIcon color="action" />
              </IconButton>
            </div>
            <h3>Richard Woessner III</h3>

            <div>
              <Link to="about" spy={true} smooth={true} offset={-15}>
                <Button color="inherit">About-Me</Button>
              </Link>
              <Link>
                <Button onClick={this.props.scrollToSlide(2)} color="inherit">My-Work</Button>
              </Link>
              <Link to="interests" spy={true} smooth={true}>
                <Button color="inherit">Interests</Button>
              </Link>
              <Link to="contact" spy={true} smooth={true}>
                <Button color="inherit">Contact-Me</Button>
              </Link>
            </div>
          </Grid>
        </Toolbar>
      </AppBar>
    );
  }
}

export default Header;
